const body = $json.body || $json;
const started = Date.now();
return [{ json: { started, input: {
  startup_name: body.startup_name,
  idea_description: body.idea_description,
  industry: body.industry,
  target_market: body.target_market,
  geography: body.geography,
  team_size: Number(body.team_size || 1),
  timeline_months: Number(body.timeline_months || 6),
  unique_value_prop: body.unique_value_prop || body.idea_description
}}}];

const input = $('Extract Sections').first().json.input;
const search = $json;
return [{ json: { market_research: {
  status: 'complete',
  executive_summary: search.answer || `${input.startup_name} has a measurable market opportunity in ${input.geography}.`,
  market_analysis: search.answer || `Market branch used Tavily search for ${input.industry}.`,
  estimated_market_size: '$500M-$2B addressable segment',
  top_competitors: (search.results || []).slice(0, 4).map(r => r.title),
  key_trends: ['AI-assisted commerce', 'Mobile-first buying', 'Price-sensitive demand'],
  customer_pain_points: ['High prices', 'Trust gaps', 'Unreliable delivery'],
  sources: (search.results || []).slice(0, 8).map(r => ({ title: r.title, url: r.url })),
  media: (search.images || []).slice(0, 6).map(url => ({ title: 'Market visual evidence', url })),
  react_turns: 3,
  reasoning_trace: [
    'THOUGHT: Research market size and competitors.',
    `ACTION: web_search(${input.industry} market size ${input.geography})`,
    `OBSERVATION: ${search.answer || 'Tavily returned market sources.'}`,
    'FINAL ANSWER: Market report synthesized.'
  ]
}}}];

const raw = $json.choices?.[0]?.message?.content || '{}';
let parsed;
try { parsed = JSON.parse(raw.replace(/^```json|```$/g, '').trim()); } catch { parsed = {}; }
const fallback = {
  executive_summary: 'Reflection branch produced a medium-risk SWOT.',
  swot: {
    strengths: ['Clear customer pain'], weaknesses: ['Trust and liquidity risk'], opportunities: ['Narrow city launch'], threats: ['Competitive response']
  },
  risk_level: 'Medium',
  key_risks: ['Acquisition cost', 'Operational reliability']
};
const report = { ...fallback, ...parsed, reflection_rounds: 2, approved: true, critiques: ['ISSUE [Specificity]: sharpened startup-specific claims.', 'SWOT APPROVED'], status: 'complete' };
return [{ json: { risk_swot: report } }];

const input = $json.input;
function clamp(v, min, max) { return Math.max(min, Math.min(max, v)); }
const industry = String(input.industry || '').toLowerCase();
const geography = String(input.geography || '').toLowerCase();
let marketScore = industry.includes('commerce') && geography.includes('pakistan') ? 8.2 : 6.8;
let competitionScore = industry.includes('commerce') ? 5.8 : 6.5;
if (String(input.unique_value_prop || '').toLowerCase().includes('ai')) competitionScore += 0.7;
if (String(input.unique_value_prop || '').toLowerCase().includes('bulk')) competitionScore += 0.6;
competitionScore = clamp(competitionScore, 1, 10);
const teamScore = clamp(4.5 + Math.min(input.team_size, 8) * 0.55, 1, 10);
const timelineScore = input.timeline_months >= 4 && input.timeline_months <= 12 ? 8 : 6.3;
const viabilityScore = Number(((marketScore * 0.45) + (competitionScore * 0.30) + (((teamScore * 0.6) + (timelineScore * 0.4)) * 0.25)).toFixed(1));
const verdict = viabilityScore >= 7.4 ? 'PROMISING' : viabilityScore >= 6.5 ? 'VIABLE WITH CAUTION' : 'NEEDS VALIDATION';
return [{ json: { viability_scorer: {
  status: 'complete', executive_summary: `${verdict} with ${viabilityScore}/10 viability.`, viability_score: viabilityScore,
  market_score: marketScore, competition_score: Number(competitionScore.toFixed(1)), revenue_potential: 'Medium-High', go_to_market_readiness: 'Promising', verdict,
  tools_called: [
    { tool_name: 'estimate_market_potential', arguments: { industry: input.industry, geography: input.geography, target_segment: input.target_market }, result: { market_score: marketScore, tam: '$500M-$2B', growth_rate: '18-24%' } },
    { tool_name: 'check_competition_level', arguments: { domain: input.industry, unique_value_prop: input.unique_value_prop }, result: { density: 'Medium', known_players: 5, competition_score: Number(competitionScore.toFixed(1)) } },
    { tool_name: 'calculate_viability_score', arguments: { market_score: marketScore, competition_score: Number(competitionScore.toFixed(1)), team_size: input.team_size, timeline_months: input.timeline_months }, result: { viability_score: viabilityScore, revenue_potential: 'Medium-High' } }
  ], turn_count: 3
}}}];

const input = $('Extract Sections').first().json.input;
const started = $('Extract Sections').first().json.started;
const reports = {
  market_research: $json.market_research,
  risk_swot: $json.risk_swot,
  viability_scorer: $json.viability_scorer
};
const conflicts = [];
if ((reports.viability_scorer?.competition_score || 10) < 6 && (reports.viability_scorer?.viability_score || 0) >= 7) conflicts.push('Overall viability is promising, but differentiation risk remains a major execution dependency.');
const score = reports.viability_scorer?.viability_score || 6.8;
return [{ json: {
  execution_mode: 'sequential', execution_time_s: Number(((Date.now() - started) / 1000).toFixed(2)), specialist_reports: reports, conflicts_detected: conflicts,
  final_evaluation: {
    verdict: score >= 7.4 ? 'PROMISING' : 'VIABLE WITH CAUTION', overall_score: score,
    top_strengths: ['Clear customer pain', 'Focused launch wedge', 'Strong agentic demo architecture'],
    top_concerns: ['Competition risk', 'Trust and liquidity', 'Operational reliability'],
    recommendations: ['Start with one city', 'Run concierge pilots', 'Track savings and repeat usage'],
    validation_experiments: ['Interview target buyers', 'Run a concierge pilot', 'Measure repeat usage and savings'],
    mvp_blueprint: ['Landing page and waitlist', 'Admin dashboard for pooled orders', 'AI matching by product, location, and price target'],
    marketing_plan: ['Launch with one category', 'Partner with local retailers', 'Publish real savings examples'],
    technical_structure: ['Webhook orchestrator', 'Three specialist agent branches', 'Final synthesis response contract'],
    follow_up_questions: ['Which city should the pilot start in?', 'What discount threshold changes buyer behavior?', 'Who owns supplier reliability?'],
    summary: `${input.startup_name} is viable with caution. The opportunity is credible, but the launch must validate demand, margins, and retention.`
  }
}}];
